import{c as t,Q as a,j as o,m as r}from"./chunks/framework.CdiUUa3G.js";const m=JSON.parse('{"title":"RFC-014 — Tiangong Explorer · 3D model pipeline & module pickability","description":"","frontmatter":{},"headers":[],"relativePath":"rfc/RFC-014.md","filePath":"rfc/RFC-014.md"}'),i={name:"rfc/RFC-014.md"};function s(n,e,l,d,c,h){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="rfc-014-—-tiangong-explorer-·-3d-model-pipeline-module-pickability" tabindex="-1">RFC-014 — Tiangong Explorer · 3D model pipeline &amp; module pickability <a class="header-anchor" href="#rfc-014-—-tiangong-explorer-·-3d-model-pipeline-module-pickability" aria-label="Permalink to &quot;RFC-014 — Tiangong Explorer · 3D model pipeline &amp; module pickability&quot;">​</a></h1><p><em>Orrery · Open RFC · v0.1 · May 2026</em></p><blockquote><p><strong>Status:</strong> Draft <strong>Author:</strong> product <strong>Closes into:</strong> ADR-048 (model source + asset pipeline), ADR-049 (module-pick strategy + LOD), ADR-050 (low-end-device fallback) <strong>Slice gate:</strong> v0.5 <strong>Why this is an RFC:</strong> PRD-011 promises a rotatable 3D Tiangong where every module is clickable, panelled, and historically attributed — the same playbook as <code>/iss</code>. The technical questions cluster the same way: <em>model source</em> (no NASA-3D Resources analogue is available for Tiangong because of the US Wolf Amendment, so the pipeline diverges from RFC-013 here), <em>picking</em> (mesh-per-pressurised-module + Chinarm; trusses are minimal on Tiangong so the truss-merge complexity from <code>/iss</code> is reduced), and <em>fallback</em> (the <code>?view=list</code> + heuristic auto-fallback pattern from ADR-042 should port cleanly).</p></blockquote><hr><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>Tiangong is China&#39;s modular space station, fully assembled October 2022, continuously crewed since June 2022. Compared to ISS:</p><table tabindex="0"><thead><tr><th></th><th>ISS</th><th>Tiangong</th></tr></thead><tbody><tr><td>Pressurised modules</td><td>17</td><td>3 (Tianhe / Wentian / Mengtian)</td></tr><tr><td>Visiting vehicle types</td><td>7 (Soyuz, Progress, Crew Dragon, Cargo Dragon, Cygnus, HTV-X, Starliner)</td><td>2 (Shenzhou crew, Tianzhou cargo)</td></tr><tr><td>Robotic arm</td><td>Canadarm2 + JEM-RMS</td><td>Chinarm + experimental small arm</td></tr><tr><td>Solar arrays</td><td>8 wings on outboard truss</td><td>2 large wings per lab module (4 total)</td></tr><tr><td>Truss complex</td><td>Significant (P0–P6, S0–S6)</td><td>Minimal — modules carry their own avionics</td></tr></tbody></table><p>Tiangong is <em>simpler</em> than ISS to model — fewer modules, fewer visitors, less truss complexity. The work pattern from <code>/iss</code> (PRD-010 / RFC-013 / ADR-040–042) ports directly with proportional simplification.</p><p>The one place Tiangong is <em>harder</em> is asset sourcing for any future Phase-B-style GLB swap — see OQ-1.</p><p>PRD-011 wants:</p><ul><li>3 pressurised modules + Chinarm individually clickable</li><li>2 visiting vehicles individually clickable</li><li>Mobile-friendly, INDEX drawer co-visible</li><li>Visually faithful to the canonical T-shape silhouette</li></ul><hr><h2 id="open-questions" tabindex="-1">Open Questions <a class="header-anchor" href="#open-questions" aria-label="Permalink to &quot;Open Questions&quot;">​</a></h2><h3 id="oq-1-—-where-does-the-model-come-from" tabindex="-1">OQ-1 — Where does the model come from? <a class="header-anchor" href="#oq-1-—-where-does-the-model-come-from" aria-label="Permalink to &quot;OQ-1 — Where does the model come from?&quot;">​</a></h3><p>ISS / RFC-013 had four candidates including NASA-3D Resources. For Tiangong:</p><table tabindex="0"><thead><tr><th>Option</th><th>Source</th><th>Licence</th><th>Tris budget</th><th>Authoring cost</th></tr></thead><tbody><tr><td><strong>A. Code-built proxy</strong> (mirrors ADR-040 V1)</td><td>Hand-built cylinders/boxes from `tiangong-modules.json`</td><td>Project-owned</td><td>~2,000 tris</td><td>~1 session</td></tr><tr><td><strong>B. CMSA / CNSA-released model</strong></td><td>Chinese state agencies sometimes release station visualisations; license terms unclear</td><td>PRC government open-content; needs vetting per ADR-046 / ADR-047</td><td>Variable</td><td>~1 day source + vet + cleanup</td></tr><tr><td><strong>C. Sketchfab community model (CC-BY)</strong></td><td>Community-authored Tiangong models</td><td>CC-BY (with attribution)</td><td>Variable</td><td>~1 day import + cleanup</td></tr><tr><td><strong>D. Custom Blender model from scratch</strong></td><td>Hand-authored</td><td>Project-owned (cleanest)</td><td>Target ~10k tris</td><td>~1 week</td></tr><tr><td><strong>E. NASA-3D Resources</strong></td><td>—</td><td>—</td><td>—</td><td><strong>Unavailable.</strong> Wolf Amendment legally prohibits NASA cooperation with Chinese space programmes; no NASA-authored Tiangong models exist.</td></tr></tbody></table><p><strong>Recommendation: A for V1, defer GLB-style swap to V1.5 / V2 via a separate RFC.</strong> The code-built proxy is faster to ship, has zero asset-sourcing risk, and produces a recognisable T-shape silhouette with very few primitives (3 cylinders + 4 wings + 1 arm). A future GLB swap can pick from B / C / D when the credits-rollout work has matured the provenance pipeline enough to vet Chinese-state imagery / models cleanly.</p><p>This locks into ADR-048 alongside the nav slot.</p><hr><h3 id="oq-2-—-module-pickability-mesh-per-module-or-pick-atlas" tabindex="-1">OQ-2 — Module pickability: mesh-per-module or pick atlas? <a class="header-anchor" href="#oq-2-—-module-pickability-mesh-per-module-or-pick-atlas" aria-label="Permalink to &quot;OQ-2 — Module pickability: mesh-per-module or pick atlas?&quot;">​</a></h3><p>PRD-011 wants 3 modules + Chinarm clickable. Same architectural choices as RFC-013 OQ-2.</p><table tabindex="0"><thead><tr><th>Option</th><th>How it works</th><th>Tris cost</th><th>Per-module operations</th><th>Memory</th></tr></thead><tbody><tr><td><strong>A. Mesh-per-module</strong></td><td>Each module is a separate <code>THREE.Mesh</code> in a Group; Raycaster intersects against the module list</td><td>+0</td><td>Trivial (<code>mesh.userData.moduleId</code>)</td><td>One draw call per module = ~5 draw calls (3 modules + Chinarm + arrays)</td></tr><tr><td><strong>B. Single mesh + UV pick atlas</strong></td><td>Unified mesh + colour-coded atlas; pick by reading colour</td><td>-0</td><td>Offscreen render on every pick</td><td>Latency hit per click</td></tr><tr><td><strong>C. Mesh-per-module + visiting fleet pickable</strong></td><td>Each station module + each visitor as its own pickable group</td><td>+0</td><td>Identical to ISS visitor pipeline</td><td>~7 draw calls (3 + arm + 2 visitors + arrays merged)</td></tr></tbody></table><p><strong>Recommendation: C</strong> — mirror the ISS pattern exactly. The visiting fleet (Shenzhou + Tianzhou) gets <code>userData.issPickable = true</code> with <code>userData.moduleId = &#39;shenzhou&#39; | &#39;tianzhou&#39;</code>, same shape as the ISS visitor wiring. Total ~7 draw calls is comfortably under any meaningful budget.</p><p>This locks into ADR-049.</p><hr><h3 id="oq-3-—-low-end-device-fallback" tabindex="-1">OQ-3 — Low-end-device fallback <a class="header-anchor" href="#oq-3-—-low-end-device-fallback" aria-label="Permalink to &quot;OQ-3 — Low-end-device fallback&quot;">​</a></h3><p>Identical question to RFC-013 OQ-3 / ADR-042. PRD-011 promises <code>?view=list</code> plus heuristic auto-fallback (no WebGL · low memory · sustained sub-20 fps).</p><p><strong>Recommendation: copy ADR-042 verbatim.</strong> Same detection rules, same URL override, same INDEX drawer behaviour for the 3D path.</p><p>This locks into ADR-050.</p><hr><h3 id="oq-4-—-earth-backdrop-in-v1" tabindex="-1">OQ-4 — Earth backdrop in V1? <a class="header-anchor" href="#oq-4-—-earth-backdrop-in-v1" aria-label="Permalink to &quot;OQ-4 — Earth backdrop in V1?&quot;">​</a></h3><p>Same as RFC-013 OQ-4. Static Earth limb behind the station, reusing the existing <code>2k_earth_daymap.jpg</code>.</p><p><strong>Recommendation: B (static Earth limb)</strong> — matches <code>/iss</code> behaviour exactly. No new assets.</p><hr><h3 id="oq-5-—-chinarm-separately-pickable" tabindex="-1">OQ-5 — Chinarm separately pickable? <a class="header-anchor" href="#oq-5-—-chinarm-separately-pickable" aria-label="Permalink to &quot;OQ-5 — Chinarm separately pickable?&quot;">​</a></h3><p>Tiangong&#39;s robotic arms:</p><ul><li><strong>Chinarm</strong> (Space Station Remote Manipulator System / 空间站机械臂) — 10 m primary arm, base on Tianhe / Wentian. Iconic, equivalent to Canadarm2 on ISS.</li><li><strong>Small experimental arm</strong> (Experimental Module Manipulator) — 5 m secondary arm, attached to Wentian. Used for fine-grained payload work.</li></ul><table tabindex="0"><thead><tr><th>Option</th><th>V1 scope</th></tr></thead><tbody><tr><td><strong>A. Chinarm pickable, small arm not</strong></td><td>Mirrors ISS V1 (Canadarm2 only)</td></tr><tr><td><strong>B. Both arms separately pickable</strong></td><td>+1 click target</td></tr><tr><td><strong>C. Neither pickable in V1</strong></td><td>Smaller scope but loses an iconic surface</td></tr></tbody></table><p><strong>Recommendation: A for V1.</strong> Chinarm is the iconic surface; the small arm is fine as visual decoration on Wentian. Promote to B if user research surfaces curiosity about the small arm.</p><hr><h3 id="oq-6-—-lod-level-of-detail-strategy" tabindex="-1">OQ-6 — LOD (level of detail) strategy <a class="header-anchor" href="#oq-6-—-lod-level-of-detail-strategy" aria-label="Permalink to &quot;OQ-6 — LOD (level of detail) strategy&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Option</th><th>Cost</th><th>Benefit</th></tr></thead><tbody><tr><td><strong>A. Single LOD</strong></td><td>0</td><td>Simplest</td></tr><tr><td><strong>B. Two-level LOD</strong></td><td>+1 day</td><td>Smoother low-end performance</td></tr></tbody></table><p><strong>Recommendation: A.</strong> Tiangong&#39;s ~2,000-tri proxy is so small that LOD has no meaningful payoff. Don&#39;t optimise prematurely.</p><hr><h3 id="oq-7-—-where-does-tiangong-sit-in-the-nav" tabindex="-1">OQ-7 — Where does Tiangong sit in the nav? <a class="header-anchor" href="#oq-7-—-where-does-tiangong-sit-in-the-nav" aria-label="Permalink to &quot;OQ-7 — Where does Tiangong sit in the nav?&quot;">​</a></h3><p>Current nav (post-PRD-010): <code>EXPLORE → MISSIONS → PLAN → FLY → EARTH → ISS → MOON → MARS</code>.</p><p>Adding Tiangong:</p><ul><li>After ISS (preserves &quot;near-Earth crewed habitats&quot; cluster — Earth → ISS → Tiangong)</li><li>Before ISS (treat Tiangong as the more recent station, but breaks the historical sequence)</li><li>After MARS (treat as the tail of the catalogue)</li></ul><p><strong>Recommendation: After ISS.</strong> Final order: <code>EXPLORE → MISSIONS → PLAN → FLY → EARTH → ISS → TIANGONG → MOON → MARS</code>. Both stations sit in LEO; placing them adjacent groups the LEO-habitat cluster cleanly.</p><p>This locks into ADR-048 alongside the asset-pipeline decision.</p><hr><h2 id="decision-criteria" tabindex="-1">Decision criteria <a class="header-anchor" href="#decision-criteria" aria-label="Permalink to &quot;Decision criteria&quot;">​</a></h2><p>We accept the resolution when:</p><ol><li>The 3D scene renders ~2,000 station tris (well under any meaningful budget) at ≥ 30 fps on a baseline 2020 mobile device.</li><li>All 3 pressurised modules + Chinarm + 2 visiting vehicles are individually pickable with no false-positives.</li><li><code>?view=list</code> fallback path renders all panel content without WebGL.</li><li>Heuristic auto-fallback flips to list view without flicker on detected low-end devices.</li><li>Earth backdrop doesn&#39;t crash low-end devices (reusing the proven <code>/iss</code> asset).</li><li>INDEX drawer co-visible with canvas (matching <code>/iss</code> post-V1 layout, not a binary view-mode flip).</li><li>Module credits (CMSA / CNSA / Wikimedia mirrors) are recorded per ADR-046 / ADR-047.</li></ol><hr><h2 id="closure-path" tabindex="-1">Closure path <a class="header-anchor" href="#closure-path" aria-label="Permalink to &quot;Closure path&quot;">​</a></h2><ul><li><strong>ADR-048</strong> — Asset pipeline: code-built proxy + nav slot after ISS. Earth backdrop reusing <code>2k_earth_daymap.jpg</code>. Future GLB swap deferred to a separate RFC.</li><li><strong>ADR-049</strong> — Module pickability: mesh-per-pressurised-module + Chinarm + visiting-fleet. ~7 draw calls.</li><li><strong>ADR-050</strong> — Low-end-device fallback: copies ADR-042&#39;s rules verbatim.</li></ul><p>Multi-LOD (OQ-6 option B), small-arm pickability (OQ-5 option B), and the future Phase-B-style GLB swap all deferred to V1.5 / V2.</p><hr><p><em>Orrery · RFC-014 · v0.1 · Open. Update on closure with the ADR numbers landed.</em></p>',60)])])}const u=t(i,[["render",s]]);export{m as __pageData,u as default};
